void build(ll id,ll l, ll r)
{
	if(l > r) return;

	if(l == r)
	{
		st[id].mxi = l;
		return;
	}

	ll m = l + (r - l) / 2;

	build(2*id+1, l, m);
	build(2*id+2, m+1, r);

	st[id] = merge(st[2*id+1], st[2*id+2]);
