struct SegTree {
    vector<Node> t;
    int size;
    SegTree(int size) : size(size) {
        int i = 1;
        while ((1 << i) < size) ++i;
        t.resize((1 << (i + 1)));
        build(0, 0, size);
    }

    Node merge(Node& l, Node& r) {
        Node res;
        res.val = l.val + r.val;
        return res;
    };

    void build(int v, int l, int r) {
        if (l + 1 == r) {
            t[v].val = 1;
            return;
        }

        int m = l + (r - l) / 2;
        build(2 * v + 1, l, m);
        build(2 * v + 2, m, r);

        t[v] = merge(t[2 * v + 1], t[2 * v + 2]);
    }

    void push(int v, int l, int r) {
        if (!t[v].mod) return;
        t[v].val = 0;
        if (r - l > 1) {
