        push(v, l, r);
        if (l >= b || r <= a) return 0;
        if (a <= l && r <= b) return t[v].val;

        int m = l + (r - l) / 2;

        return (get(2 * v + 1, l, m, a, b) + get(2 * v + 2, m, r, a, b));
    }


