struct Node {
    ll val = 0;
    bool mod = false;
};


struct SegTree {
    vector<Node> t;
    int size;
    SegTree(int size) : size(size) {
        int i = 1;
        while ((1 << i) < size) ++i;
        t.resize((1 << (i + 1)));
        build(0, 0, size);
    }

    Node merge(Node& l, Node& r) {
        Node res;
        res.val = l.val + r.val;
        return res;
    };

    void build(int v, int l, int r) {
        if (l + 1 == r) {
            t[v].val = 1;
            return;
        }

        int m = l + (r - l) / 2;
        build(2 * v + 1, l, m);
        build(2 * v + 2, m, r);

        t[v] = merge(t[2 * v + 1], t[2 * v + 2]);
    }

    void push(int v, int l, int r) {
        if (!t[v].mod) return;
        t[v].val = 0;
        if (r - l > 1) {
            t[2 * v + 1].mod = true;
            t[2 * v + 2].mod = true;
        }

        t[v].mod = false;
    }

    ll get(int v, int l, int r, int a, int b) {
        push(v, l, r);
        if (l >= b || r <= a) return 0;
        if (a <= l && r <= b) return t[v].val;

        int m = l + (r - l) / 2;

        return (get(2 * v + 1, l, m, a, b) + get(2 * v + 2, m, r, a, b));
    }


    void upd(int v, int l, int r, int a, int b) {
        push(v, l, r);
        if (r <= a || l >= b) return;
        if (a <= l && r <= b) {
            t[v].mod = true;
            push(v, l, r);
            return;
        }

        int m = (r + l) >> 1;
        upd(2 * v + 1, l, m, a, b);
        upd(2 * v + 2, m, r, a, b);
        t[v] = merge(t[2 * v + 1], t[2 * v + 2]);
    }


    void upd(int l, int r) {
        upd(0, 0, size, l, r);
    }

    ll get(int l, int r) {
        return get(0, 0, size, l, r);
    }
};




